---
/**
 * Site header with responsive nav and mobile hamburger.
 * Uses CSS custom properties only — no hardcoded colors/sizes.
 */
const navLinks = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Ministries', href: '/ministries' },
  { label: 'Sermons', href: '/sermons' },
  { label: 'Contact', href: '/contact' },
];
---

<header class="site-header">
  <div class="header-inner">
    <a href="/" class="logo" aria-label="FICCC — Home">
      <span class="logo-text">FICCC</span>
    </a>

    <button
      class="hamburger"
      type="button"
      aria-expanded="false"
      aria-controls="nav-menu"
      aria-label="Toggle navigation menu"
    >
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
    </button>

    <nav id="nav-menu" class="nav" aria-label="Main navigation">
      <ul class="nav-list" role="list">
        {navLinks.map((link) => (
          <li><a href={link.href} class="nav-link">{link.label}</a></li>
        ))}
      </ul>
      <button class="lang-toggle" type="button" aria-label="EN / 中文: Switch language">
        EN / 中文
      </button>
    </nav>
  </div>
</header>

<style>
  .site-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background-color: var(--color-bg);
    border-bottom: 1px solid var(--color-stone);
  }

  .header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: var(--max-width);
    margin-inline: auto;
    padding: var(--space-4) var(--space-6);
  }

  /* Logo */
  .logo {
    text-decoration: none;
    color: var(--color-ink);
  }
  .logo-text {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    font-weight: 700;
    letter-spacing: 0.04em;
  }

  /* Desktop nav */
  .nav {
    display: flex;
    align-items: center;
    gap: var(--space-6);

---
/**
 * Site footer — church info, nav links, copyright.
 * Uses CSS custom properties only.
 */
const currentYear = new Date().getFullYear();

const footerNav = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Ministries', href: '/ministries' },
  { label: 'Sermons', href: '/sermons' },
  { label: 'Contact', href: '/contact' },
];
---

<footer class="site-footer">
  <div class="footer-inner">
    <!-- Church identity -->
    <div class="footer-col footer-identity">
      <p class="footer-name-en">First Ithaca Chinese Christian Church</p>
      <p class="footer-name-zh" lang="zh">伊的家華人基督教會</p>
      <address class="footer-address">
        309 College Ave<br />
        Ithaca, NY 14850
      </address>
    </div>

    <!-- Service times -->
    <div class="footer-col footer-services">
      <h2 class="footer-heading">Service Times</h2>
      <ul class="footer-list" role="list">
        <li>Sunday Worship: 10:00 AM</li>
        <li>Sunday School: 11:30 AM</li>
        <li>Friday Fellowship: 7:30 PM</li>
      </ul>
    </div>

    <!-- Navigation -->
    <nav class="footer-col footer-nav" aria-label="Footer navigation">
      <h2 class="footer-heading">Links</h2>
      <ul class="footer-list" role="list">
        {footerNav.map((link) => (
          <li><a href={link.href} class="footer-link">{link.label}</a></li>
        ))}
      </ul>
    </nav>
  </div>

  <div class="footer-bottom">
    <p>&copy; {currentYear} First Ithaca Chinese Christian Church. All rights reserved.</p>
  </div>
</footer>

<style>
  .site-footer {
    background-color: var(--color-bg-dark);
    color: var(--color-bg);
    margin-top: auto;
  }

  .footer-inner {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(14rem, 1fr));
    gap: var(--space-8);
    max-width: var(--max-width);
    margin-inline: auto;
    padding: var(--space-12) var(--space-6) var(--space-8);
  }

  .footer-name-en {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    font-weight: 700;
    color: var(--color-bg);
    margin-block-end: var(--space-1);
  }
  .footer-name-zh {
    font-family: var(--font-cjk);
    font-size: var(--text-zh-base);
    color: var(--color-stone);
    margin-block-end: var(--space-4);
  }
  .footer-address {
    font-style: normal;
    font-size: var(--text-sm);
    color: var(--color-stone);
    line-height: var(--leading-relaxed);
  }

  .footer-heading {
    font-family: var(--font-heading);
    font-size: var(--text-sm);
    font-weight: 700;
    color: var(--color-bg);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin-block-end: var(--space-4);
  }

  .footer-list {
    list-style: none;
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
    font-size: var(--text-sm);
    color: var(--color-stone);
  }

  .footer-link {
    color: var(--color-stone);
    text-decoration: none;
    transition: color var(--transition);
  }
  .footer-link:hover,
  .footer-link:focus-visible {
    color: var(--color-terracotta);
  }
  .footer-link:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: var(--radius-sm);
  }

  .footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    max-width: var(--max-width);
    margin-inline: auto;
    padding: var(--space-6) var(--space-6);
    font-size: var(--text-xs);
    color: var(--color-stone);
    text-align: center;
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ServiceTimes from '../components/ServiceTimes.astro';
import ImageMosaic from '../components/ImageMosaic.astro';
import Pillars from '../components/Pillars.astro';
import Card from '../components/Card.astro';
import NextSteps from '../components/NextSteps.astro';
import { getHomePage, getSermons, getEvents, urlForImage } from '../lib/sanity';

const title = 'First Ithaca Chinese Christian Church | 伊的家華人基督教會';
const description =
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY. Sunday gathering at 9:45am, 429 Mitchell Street.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let homePage: Awaited<ReturnType<typeof getHomePage>> = null;
let sermons: Awaited<ReturnType<typeof getSermons>> = [];
let events: Awaited<ReturnType<typeof getEvents>> = [];

try {
  [homePage, sermons, events] = await Promise.all([
    getHomePage('en'),
    getSermons('en'),
    getEvents('en'),
  ]);
} catch {
  // Sanity unreachable (placeholder project, no network, etc.) — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackServiceTimes = [
  { label: 'Sunday Gathering', time: '9:45 AM' },
  { label: 'Sunday School', time: '11:15 AM' },
];

const fallbackPillars = [
  {
    title: 'Rooted in Scripture',
    description:
      "We hold to the Bible as God's inspired Word and the foundation for all of life and faith.",
  },
  {
    title: 'Christ-Centered Community',
    description:
      'We gather as a Christ-centered community, welcoming students, families, and neighbors of all backgrounds.',
  },
  {
    title: 'Bridging Cultures',
    description:
      'We celebrate our Chinese heritage while building a church home that bridges cultures and generations.',
  },
];

const fallbackNextSteps = [
  {
    title: 'Plan Your Visit',
    body: 'Join us Sunday at 9:45 AM. Learn what to expect and how to find us.',
    href: '/visit',
  },
  {
    title: 'Get Connected',
    body: 'Discover small groups, ministries, and ways to grow alongside others.',
    href: '/ministries',
  },
  {
    title: 'Watch Sermons',
    body: 'Catch up on recent messages or explore a teaching series.',
    href: '/sermons',
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = homePage?.heroImage
  ? urlForImage(homePage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = homePage?.heroTitle || 'Welcome Home';
const heroSubtitle =
  homePage?.heroSubtitle ||
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.';
const heroCtaText = homePage?.heroCtaText || 'Plan Your Visit';
const heroCtaHref = homePage?.heroCtaHref || '/visit';

const serviceTimes =
  homePage?.serviceTimes && homePage.serviceTimes.length > 0
    ? homePage.serviceTimes
    : fallbackServiceTimes;

const mosaicImages =
  homePage?.mosaicImages && homePage.mosaicImages.length > 0
    ? homePage.mosaicImages.map((img) => ({
        src: urlForImage(img, { width: 800 }),
        alt: img.alt || '',
      }))
    : Array.from({ length: 6 }, (_, i) => ({
        src: `/images/placeholder-${i + 1}.svg`,
        alt: `Church life ${i + 1}`,
      }));

const pillars =
  homePage?.pillars && homePage.pillars.length > 0
    ? homePage.pillars.map((p) => ({
        title: p.title,
        description: p.description || '',
      }))
    : fallbackPillars;

const nextSteps =
  homePage?.nextSteps && homePage.nextSteps.length > 0
    ? homePage.nextSteps.map((s) => ({
        title: s.title,
        body: s.body || '',
        href: s.href || '#',
        image: s.image ? urlForImage(s.image, { width: 600 }) : undefined,
      }))
    : fallbackNextSteps;

// ---------- Featured content ----------
const latestSermon = sermons[0] ?? null;
const nextEvent = events[0] ?? null;
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      ctaText={heroCtaText}
      ctaHref={heroCtaHref}
      backgroundImage={heroImage}
    />

    <ServiceTimes times={serviceTimes} />

    <section class="mosaic-section" aria-label="Church Life">
      <div class="mosaic-section__inner">
        <ImageMosaic images={mosaicImages} />
      </div>
    </section>

    <Pillars pillars={pillars} />

    {(latestSermon || nextEvent) && (
      <section class="featured" aria-label="Featured">
        <div class="featured__inner">
          <h2 class="featured__heading">Stay Connected</h2>
          <div class="featured__grid">
            {latestSermon && (
              <Card
                title={latestSermon.title}
                body={latestSermon.speaker ? `Speaker: ${latestSermon.speaker}` : 'Latest sermon'}
                href="/sermons"
              />
            )}
            {nextEvent && (
              <Card
                title={nextEvent.title}
                body={nextEvent.date ? `Date: ${nextEvent.date}` : 'Upcoming event'}
                href="/events"
              />
            )}
          </div>
        </div>
      </section>
    )}

    <NextSteps steps={nextSteps} />
  </main>
</BaseLayout>

<style>
  .mosaic-section {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .mosaic-section__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .featured__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-12);
  }

  .featured__grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-8);
  }

  @media (max-width: 768px) {
    .featured__grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .featured__heading {
      font-size: var(--text-2xl);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { getAboutPage, portableTextToHtml, urlForImage } from '../../lib/sanity';

const title = 'Who We Are | FICCC';
const description =
  'Learn about First Ithaca Chinese Christian Church — our history, mission, and community.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackHeading = 'Who We Are';
const fallbackBody = `
<p>First Ithaca Chinese Christian Church (FICCC) was founded in 1968 by a small group of Chinese graduate students and scholars at Cornell University who longed for a Christ-centered community where they could worship in their heart language while welcoming the broader Ithaca community.</p>
<p>Over the decades the church has grown into a multigenerational, multicultural congregation that bridges Chinese heritage and American life. We gather every Sunday at 429 Mitchell Street for worship, teaching, and fellowship — in English and Mandarin — serving students, families, and neighbors throughout the Finger Lakes region.</p>
<p>Our mission is to glorify God by making disciples of Jesus Christ who love God wholeheartedly, love one another sacrificially, and reach out to the world with the Gospel. We believe the local church is God's primary instrument for advancing His kingdom, and we are committed to equipping every member for a life of faithful service.</p>
<p>Whether you are a longtime resident of Ithaca, a visiting scholar, or a student far from home, there is a place for you at FICCC. We invite you to come as you are and experience the warmth of Christ's love in community.</p>
`.trim();

const fallbackVisionHeading = 'Our Vision';
const fallbackVisionHtml = `
<p><strong>Develop Humble Servants Who Love the Lord, Love the Lost, Love the Local Church — For the Rest of Their Lives.</strong></p>
<p>Most of the students and scholars who walk through our doors will only be in Ithaca for a few years. But we believe that what happens during those years — the habits of worship, the depth of community, the encounters with Scripture — can shape the trajectory of an entire life.</p>
<p>Our vision is to nurture Christ-followers who don't just "do church" while they're here, but who carry the marks of discipleship wherever they go: into careers, families, churches, and communities around the world.</p>
`.trim();

const fallbackStats = [
  { value: '~150', label: 'Congregation Members' },
  { value: '~20', label: 'Baptisms Per Year' },
  { value: '18', label: 'Full-Time Ministers Sent' },
  { value: '40+', label: 'Years in Ithaca' },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heading = aboutPage?.whoWeAreHeading || fallbackHeading;
const bodyHtml = aboutPage?.whoWeAreBody?.length
  ? portableTextToHtml(aboutPage.whoWeAreBody)
  : fallbackBody;
const imageUrl = aboutPage?.whoWeAreImage
  ? urlForImage(aboutPage.whoWeAreImage, { width: 800 })
  : '';

const visionHeading = aboutPage?.visionHeading || fallbackVisionHeading;
const visionHtml = aboutPage?.visionBody?.length
  ? portableTextToHtml(aboutPage.visionBody)
  : fallbackVisionHtml;

const stats =
  aboutPage?.churchStats && aboutPage.churchStats.length > 0
    ? aboutPage.churchStats
    : fallbackStats;
---

<BaseLayout title={title} description={description}>
  <main class="about">
    <section class="about__hero" aria-label="Who We Are">
      <div class="about__inner">
        <h1 class="about__heading">{heading}</h1>
        <div class="about__content">
          <div class="about__body" set:html={bodyHtml} />
          {imageUrl && (
            <div class="about__image-wrap">
              <img
                class="about__image"
                src={imageUrl}
                alt={heading}
                loading="lazy"
                width="800"
                height="533"
              />
            </div>
          )}
        </div>
      </div>
    </section>

    <!-- Vision Statement -->
    <section class="vision" aria-label="Our Vision">
      <div class="vision__inner">
        <h2 class="vision__heading">{visionHeading}</h2>
        <div class="vision__body" set:html={visionHtml} />
      </div>
    </section>

    <!-- Church Stats -->
    <section class="stats" aria-label="Church by the Numbers">
      <div class="stats__inner">
        <h2 class="stats__heading">By the Numbers</h2>
        <div class="stats__grid">
          {stats.map((stat) => (
            <div class="stats__item">
              <span class="stats__value">{stat.value}</span>
              <span class="stats__label">{stat.label}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  .about {
    padding-block: var(--space-16);
  }

  .about__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    padding-inline: var(--space-6);
  }

  .about__heading {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    color: var(--color-ink);
    margin-block-end: var(--space-8);
  }

  .about__content {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--space-10);
  }

  .about__body {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
  }

  .about__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .about__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .about__body :global(a) {
    color: var(--color-terracotta);
    text-decoration: underline;
  }

  .about__image-wrap {
    border-radius: var(--radius-lg, 0.75rem);
    overflow: hidden;
  }

  .about__image {
    width: 100%;
    height: auto;
    display: block;
    object-fit: cover;
  }

  /* ---------- Vision ---------- */
  .vision {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .vision__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .vision__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-8);
  }

  .vision__body {
    max-width: 48rem;
    margin-inline: auto;
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .vision__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .vision__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .vision__body :global(strong) {
    color: var(--color-ink);
  }

  /* ---------- Stats ---------- */
  .stats {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .stats__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .stats__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-10);
  }

  .stats__grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: var(--space-8);
    text-align: center;
  }

  .stats__item {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .stats__value {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    font-weight: 700;
    color: var(--color-terracotta);
  }

  .stats__label {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
  }

  @media (min-width: 768px) {
    .about__content {
      grid-template-columns: 3fr 2fr;
      align-items: start;
    }
  }

  @media (max-width: 767px) {
    .about__heading {
      font-size: var(--text-3xl);
    }

    .about__body {
      font-size: var(--text-base);
    }

    .vision__heading {
      font-size: var(--text-2xl);
    }

    .stats__grid {
      grid-template-columns: repeat(2, 1fr);
    }

    .stats__value {
      font-size: var(--text-3xl);
    }
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import Accordion from '../components/Accordion.astro';
import RideRequestForm from '../components/RideRequestForm.astro';
import { getVisitPage, urlForImage, portableTextToHtml } from '../lib/sanity';

const title = 'Plan Your Visit | First Ithaca Chinese Christian Church';
const description =
  'Everything you need to know for your first Sunday with us — service times, directions, parking, and what to expect.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let visitPage: Awaited<ReturnType<typeof getVisitPage>> = null;

try {
  visitPage = await getVisitPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackSchedule = [
  {
    label: 'Sunday Gathering',
    time: '9:45 AM',
    description:
      'Worship service with singing, prayer, and a message from Scripture',
  },
  {
    label: 'Sunday School',
    time: '11:15 AM',
    description:
      'Age-specific classes for children, youth, and adults',
  },
];

const fallbackWhatToExpectHtml = `
<p>Whether it's your first time at church or you've been part of a community before, you're welcome here just as you are.</p>
<p><strong>Dress code:</strong> Come as you are — most people dress casually. You'll see everything from jeans to button-downs.</p>
<p><strong>What happens on Sunday:</strong> Our gathering includes worship through singing, prayer, Scripture reading, and a sermon. Services are primarily in English with occasional bilingual elements.</p>
<p><strong>Kids are welcome:</strong> Children are always welcome in the main service. We also offer age-appropriate Sunday School classes after the gathering.</p>
<p><strong>How long is the service?</strong> The Sunday gathering typically lasts about 75 minutes.</p>
`;

const fallbackTransportationHtml = `
<p><strong>Address:</strong> 429 Mitchell Street, Ithaca, NY 14850</p>
<p><strong>Parking:</strong> Free parking is available in our lot adjacent to the building. Street parking is also available on Mitchell Street and nearby side streets.</p>
<p><strong>Near Cornell:</strong> We're a short drive from Cornell University's campus. If you're a student without a car, we'd be happy to help arrange a ride — just ask!</p>
<p><strong>Public transit:</strong> TCAT bus routes serve the area. Check <a href="https://tcatbus.com">tcatbus.com</a> for schedules.</p>
`;

const fallbackFaqItems = [
  {
    question: 'What should I wear?',
    answer:
      `There's no dress code — come as you are. Most people dress casually.`,
  },
  {
    question: 'Are children welcome?',
    answer:
      'Absolutely! Children are welcome in the main service, and we offer Sunday School classes for different age groups after the gathering.',
  },
  {
    question: 'What language is the service in?',
    answer:
      'Our services are primarily in English with occasional bilingual (English/Chinese) elements. Everyone is welcome regardless of language background.',
  },
  {
    question: 'Is there parking available?',
    answer:
      'Yes — free parking is available in our lot next to the building, and street parking is available nearby.',
  },
  {
    question: 'How long is the service?',
    answer:
      'The Sunday gathering typically lasts about 75 minutes. Sunday School classes follow at 11:15 AM and run for about 45 minutes.',
  },
  {
    question: 'How can I get connected during the week?',
    answer:
      `We'd love to help you find community! After the service, stop by the welcome table to learn about small groups, Bible studies, and other ways to connect. You can also reach out through our contact page.`,
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = visitPage?.heroImage
  ? urlForImage(visitPage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = visitPage?.heroTitle || 'Plan Your Visit';
const heroSubtitle =
  visitPage?.heroSubtitle ||
  'Everything you need to know for your first Sunday with us';

const schedule =
  visitPage?.schedule && visitPage.schedule.length > 0
    ? visitPage.schedule
    : fallbackSchedule;

const whatToExpectHtml =
  visitPage?.whatToExpect && visitPage.whatToExpect.length > 0
    ? portableTextToHtml(visitPage.whatToExpect)
    : fallbackWhatToExpectHtml;

const transportationHtml =
  visitPage?.transportation && visitPage.transportation.length > 0
    ? portableTextToHtml(visitPage.transportation)
    : fallbackTransportationHtml;

const faqItems =
  visitPage?.faqItems && visitPage.faqItems.length > 0
    ? visitPage.faqItems
    : fallbackFaqItems;

// Map FAQ items to Accordion's expected shape
const accordionItems = faqItems.map((item) => ({
  title: item.question,
  content: item.answer,
}));

const showRideRequest = visitPage?.rideRequestEnabled !== false;
