    <section class="schedule" aria-label="Sunday Schedule">
      <div class="schedule__inner">
        <h2 class="section-heading">Sunday Schedule</h2>
        <div class="schedule__grid">
          {schedule.map((item) => (
            <div class="schedule__card">
              <span class="schedule__time">{item.time}</span>
              <h3 class="schedule__label">{item.label}</h3>
              {item.description && (
                <p class="schedule__desc">{item.description}</p>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>

    <!-- What to Expect -->
    <section class="expect" aria-label="What to Expect">
      <div class="expect__inner">
        <h2 class="section-heading">What to Expect</h2>
        <div class="expect__body" set:html={whatToExpectHtml} />
      </div>
    </section>

    <!-- Transportation & Directions -->
    <section class="directions" aria-label="Transportation and Directions">
      <div class="directions__inner">
        <h2 class="section-heading">Getting Here</h2>
        <div class="directions__columns">
          <div class="directions__body" set:html={transportationHtml} />
          <div class="directions__map">
            <iframe
              title="Church location on Google Maps"
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2942.8!2d-76.5005!3d42.4440!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2z429+Mitchell+Street%2C+Ithaca%2C+NY+14850!5e0!3m2!1sen!2sus!4v1"
              width="100%"
              height="300"
              style="border:0; border-radius: var(--radius-md);"
              allowfullscreen=""
              loading="lazy"
              referrerpolicy="no-referrer-when-downgrade"
